using UnityEngine;

public class PlayerPrefsExample : MonoBehaviour
{
    // Keys for PlayerPrefs
    private const string HIGH_SCORE_KEY = "HighScore";
    private const string PLAYER_NAME_KEY = "PlayerName";
    private const string LEVEL_KEY = "CurrentLevel";
    private const string SOUND_KEY = "SoundEnabled";
    private const string MUSIC_KEY = "MusicEnabled";
    private const string VOLUME_KEY = "MasterVolume";

    void Start()
    {
        // Load saved data
        LoadGameData();

        // Test keys
        if (Input.GetKeyDown(KeyCode.S))
        {
            SaveGameData();
        }
        if (Input.GetKeyDown(KeyCode.L))
        {
            LoadGameData();
        }
        if (Input.GetKeyDown(KeyCode.C))
        {
            ClearAllData();
        }
    }

    // --- Saving Data ---

    public void SaveGameData()
    {
        PlayerPrefs.SetInt(HIGH_SCORE_KEY, 1000);
        PlayerPrefs.SetString(PLAYER_NAME_KEY, "Hero");
        PlayerPrefs.SetInt(LEVEL_KEY, 5);
        PlayerPrefs.SetInt(SOUND_KEY, 1);  // 1 = true, 0 = false
        PlayerPrefs.SetInt(MUSIC_KEY, 1);
        PlayerPrefs.SetFloat(VOLUME_KEY, 0.8f);

        // Save to disk
        PlayerPrefs.Save();

        Debug.Log("Game data saved!");
    }

    public void LoadGameData()
    {
        if (PlayerPrefs.HasKey(HIGH_SCORE_KEY))
        {
            int highScore = PlayerPrefs.GetInt(HIGH_SCORE_KEY);
            string playerName = PlayerPrefs.GetString(PLAYER_NAME_KEY, "Default");
            int level = PlayerPrefs.GetInt(LEVEL_KEY, 1);
            bool soundEnabled = PlayerPrefs.GetInt(SOUND_KEY, 1) == 1;
            bool musicEnabled = PlayerPrefs.GetInt(MUSIC_KEY, 1) == 1;
            float volume = PlayerPrefs.GetFloat(VOLUME_KEY, 1f);

            Debug.Log("=== Loaded Data ===");
            Debug.Log("High Score: " + highScore);
            Debug.Log("Player Name: " + playerName);
            Debug.Log("Level: " + level);
            Debug.Log("Sound: " + (soundEnabled ? "On" : "Off"));
            Debug.Log("Music: " + (musicEnabled ? "On" : "Off"));
            Debug.Log("Volume: " + volume);
        }
        else
        {
            Debug.Log("No saved data found. Using defaults.");
        }
    }

    public void ClearAllData()
    {
        PlayerPrefs.DeleteAll();
        Debug.Log("All PlayerPrefs data cleared!");
    }

    // --- Individual save/load methods ---

    public void SaveHighScore(int score)
    {
        PlayerPrefs.SetInt(HIGH_SCORE_KEY, score);
        PlayerPrefs.Save();
    }

    public int LoadHighScore()
    {
        return PlayerPrefs.GetInt(HIGH_SCORE_KEY, 0);
    }

    public void SavePlayerName(string name)
    {
        PlayerPrefs.SetString(PLAYER_NAME_KEY, name);
        PlayerPrefs.Save();
    }

    public string LoadPlayerName()
    {
        return PlayerPrefs.GetString(PLAYER_NAME_KEY, "Player");
    }

    public void SaveLevel(int level)
    {
        PlayerPrefs.SetInt(LEVEL_KEY, level);
        PlayerPrefs.Save();
    }

    public int LoadLevel()
    {
        return PlayerPrefs.GetInt(LEVEL_KEY, 1);
    }

    public void SaveSoundEnabled(bool enabled)
    {
        PlayerPrefs.SetInt(SOUND_KEY, enabled ? 1 : 0);
        PlayerPrefs.Save();
    }

    public bool LoadSoundEnabled()
    {
        return PlayerPrefs.GetInt(SOUND_KEY, 1) == 1;
    }

    // --- Utility methods ---

    public bool HasSavedData()
    {
        return PlayerPrefs.HasKey(HIGH_SCORE_KEY);
    }

    public void DeleteKey(string key)
    {
        PlayerPrefs.DeleteKey(key);
        Debug.Log("Deleted key: " + key);
    }

    public void PrintAllKeys()
    {
        // PlayerPrefs doesn't support enumerating keys
        Debug.Log("PlayerPrefs keys: HighScore, PlayerName, CurrentLevel, SoundEnabled, MusicEnabled, MasterVolume");
    }
}

